var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"끄응. 불편한 자세로 있었더니 멀미라도 하는 기분이군.","JPN":"ぐぬぬ。慣れない姿勢を続けていたせいか乗り物酔いでもした気分じゃ。","ENG":"Ugh. Sitting in that awkward position has me feeling queasy.","TWN":"呃嗯，因為姿勢很不舒服，感覺有點暈車。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"요 커다란 건물이 녀석들이 말한 연구소냐?","JPN":"この大きな建物が、さっき話していた研究所とやらか？","ENG":"That big building there, is that the lab they were talking about?","TWN":"這棟巨大的建築物就是妳們說的研究所嗎？"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"응. 한 번 무너졌었는데, 쓸만한 게 많아서 내 능력으로 재건시켰어.","JPN":"うん。一度崩壊したけど、使えるものが多かったから私の能力で再建した。","ENG":"Yeah. It collapsed once, but there was a lot worth salvaging, so I rebuilt it with my ability.","TWN":"嗯，之前倒塌過一次，但因為能用的東西很多，就用我的能力重建了。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"위험한 설비가 많아서 다들 필요할 때를 제외하고는 오지 않지만…….","JPN":"危険な設備が多いから、特に用事がない限り誰も来ないけど……","ENG":"There are lots of hazardous systems, so no one comes here unless they need to, but...","TWN":"因為有很多危險設備，除了有需要的時候大家都不會來……"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"딱 한 명. 주기적으로 이 시설을 방문하는 사람이 있어.","JPN":"1人だけ、定期的にこの施設を訪ねる人がいる。","ENG":"There is exactly one person who visits this facility regularly.","TWN":"但是只有一個人會定期跑來這座設施。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"이번 일도 아마 그 사람의 소행이겠지.","JPN":"今回の件も、たぶんあの人の仕業だと思う。","ENG":"This business is probably her doing too.","TWN":"這次的事應該是那個人所為。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"어느 마을이나 장난꾸러기 한 명은 있는 법이지~.","JPN":"どの村にもいたずらっ子はいるものじゃ。","ENG":"Every town has at least one troublemaker.","TWN":"每個村子都會有一個搗蛋鬼～"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"너나 민병단이나, 그 녀석 관리하느라 애 좀 먹겠구나.","JPN":"お主も民兵団も、そいつの扱いには苦労しておるようじゃな。","ENG":"You and the militia must have your hands full keeping her in line.","TWN":"妳和民兵團為了管理那個傢伙應該吃了不少苦。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"굳이 따지면 마을 사람은 아니야. 잠시 거처를 빌려주고 있을 뿐이거든.","JPN":"厳密に言うと村の人じゃないよ。しばらく生活できるように場所を貸してるだけ。","ENG":"Strictly speaking, she isn't a villager. We are just letting her stay for a while.","TWN":"如果非要追究的話，她不是村子裡的人，只是暫時借她地方住而已。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그 녀석, 이름은?","JPN":"そいつの名は？","ENG":"What is her name?","TWN":"那個傢伙的名字是？"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"레노어.","JPN":"レノア。","ENG":"Lenore.","TWN":"蕾諾雅。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"제길. 나쁜 예감은 항상 틀려가질 않는군.","JPN":"やっぱりか。悪い予感は外れることがないのう。","ENG":"Figures. My bad hunches never seem to be wrong.","TWN":"該死，不祥的預感總是不會出錯。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"……사람의 흔적.","JPN":"……人の気配。","ENG":"...Human tracks.","TWN":"……有人的痕跡。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"한 명이 아니야. 아무래도 일행이 있는 것 같아.","JPN":"1人じゃない。どうやら連れがいるみたいだね。","ENG":"It's not just one. Looks like they have company.","TWN":"不只一個人，總覺得應該是一行人。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그래. 세 명… 거기에 인간이 아닌 것의 흔적도 보이는구나.","JPN":"ああ、3人……それに、人間ではないものの痕跡もあるのう。","ENG":"Right. Three... And I can see traces of something non-human as well.","TWN":"沒錯，三個人…那裡也有不是人類的痕跡。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"여러 명이서 금지 구역을 넘어갔다면 좋은 꿍꿍이는 아닌 듯싶은데, 어떡할 거냐?","JPN":"連れ立って立入禁止エリアに入ったということは、何か良からぬことを企んでおるようじゃが……どうする？","ENG":"If several of them crossed into the off-limits zone, that cannot be for anything good. What do you want to do?","TWN":"如果是好幾個人越過禁區的話，應該是不懷好意，該怎麼辦？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L28_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"다른 민병단원들을 기다리기만 해선 늦을지도 몰라.","JPN":"他の民兵団員を待っていたら、間に合わないかもしれない。","ENG":"If we just wait for the other militia members, we might be too late.","TWN":"一直乾等其他民兵團員可能會來不及。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L29_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"조용하게 움직인다면 그만큼 들키기 싫다는 거니까…….","JPN":"静かに動いてるってことは、バレたくないということだから……","ENG":"If they are moving quietly, that means they don't want to be noticed...","TWN":"如果是安靜地行動，就代表是不想被發現……"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L30_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"시간을 주지 않는 편이 유리할 거라 생각해.","JPN":"時間を与えないほうが、有利になると思う。","ENG":"We're better off not giving them time.","TWN":"我覺得不要給她們時間會比較有利。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"동감이다. 어린 것이 야무지기까지 하니 보면 볼수록 탐나는군.","JPN":"わしも同意見じゃ。若いのに頭の回転も速いとは、見れば見るほど欲しくなるのう。","ENG":"Agreed. You are young and sharp. The more I see, the more I want to recruit you.","TWN":"我贊同，看妳小小年紀還這麼幹練，越看越感興趣。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"좋아, 미래의 제자님이 싸운다는데 지켜보고 있을 수만은 없지.","JPN":"よし。未来の弟子が戦いに臨むというのに、ただ見ているわけにはいかん。","ENG":"All right, if my future apprentice is fighting, I cannot just stand by and watch.","TWN":"很好，未來的徒弟都說要戰鬥了，總不能只是袖手旁觀。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"레노어 녀석에게 빚진 것도 있으니, 내 특별히 손을 빌려주마.","JPN":"レノアのやつには借りがあるし、特別に手伝ってやろう。","ENG":"I owe Lenore too, so I will lend you my strength.","TWN":"我對蕾諾雅那傢伙也有所虧欠，就特別助你一臂之力吧。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"침식된 이터니움이 마흔 일곱… 마흔 여덟…….","JPN":"侵食されたエタニウムが47……48……","ENG":"Forty-seven... Forty-eight Corrupted Eterniums...","TWN":"被侵蝕的永恆之金有47…48……"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"맥없는 소리로 말하지 마. 고작 이터니움 챙기는 게 뭐가 힘들다고 그렇게 투덜거려?","JPN":"力抜けた声で数えないでくれる？　たかがエタニウムを運ぶくらい、ぶつぶつ言うほど大変じゃないでしょ。","ENG":"Quit whining. You're just packing Eternium. What's so hard that you have to gripe like that?","TWN":"不要用無精打采的聲音說話，不過是拿個永恆之金有這麼累嗎？還那樣嘀嘀咕咕的？"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"HATE2"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그래. 고작 이터니움 챙기자고 지금껏 이 고생을 했지.","JPN":"まあ、その「たかがエタニウム」のわりには、随分険しい道のりではあったけど。","ENG":"Right, we went through hell all this time just to pack Eternium.","TWN":"是啊，一直以來吃了這麼多苦就只是為了要拿永恆之金。"},"stage":{"bg":"LABORATORY_03","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그런데 여기 있는 건 너무 적지 않아?","JPN":"でもここにあるのは少なすぎるんじゃない？","ENG":"But is this not way too little for what's here?","TWN":"但這裡的會不會太少？"},"stage":{"bg":"LABORATORY_03","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"시, 실험은 다른 연구소에서도 진행되었으니 선로전환기를 위한 분량은 이미 확보되었을 거예요.","JPN":"じ、実験は他の研究所でも行われていたので、線路転換器のための分はすでに確保済みだと思います。","ENG":"Th-the experiments were conducted at other labs too, so the amount for the Track Switcher should already be secured.","TWN":"其、其他研究所也有進行實驗，應該已經確保線路轉換器需要的分量了。"},"stage":{"bg":"LABORATORY_03","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"많으면 많을수록 좋으니까, 여, 여기 온 거고요.","JPN":"でも多ければ多いほどいいから、こ、ここに来たんです。","ENG":"More is always better. That's why we came here.","TWN":"因為越多越好，所、所以才會來這裡。"},"stage":{"bg":"LABORATORY_03","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L48_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"에휴, 결국 펠릭스의 뒤치다꺼리나 하는 셈이네.","JPN":"はあ、結局はフェリックスにこき使われてるのよね。","ENG":"Figures. We're basically cleaning up Felix's mess again.","TWN":"唉唷，到頭來等於是在替緋莉克絲善後。"},"stage":{"bg":"LABORATORY_03","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그런데, 시민들 눈을 피해서 이걸 전부 옮길 방법은 있어?","JPN":"でも、人にバレずにこれを全部持ち出す方法なんてあるの？","ENG":"Anyway, do we have a way to move all of this without the townsfolk seeing?","TWN":"但是有能避開市民視線，把這些全部移走的方法嗎？"},"stage":{"bg":"LABORATORY_03","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L1_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"걱정 마. 이 안에 운송용 로봇은 차고 넘치니까.","JPN":"心配しないで。輸送用のロボットはこの中にごまんとあるわ。","ENG":"Relax. There are plenty of transport robots in here.","TWN":"別擔心，這裡面多的是運送用的機器人。"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"우선 이터니움은 한곳에 모아놓고, 청동코어가 있는 방으로 가자.","JPN":"まずエタニウムを1か所に集めて、青銅コアのある部屋に行きましょう。","ENG":"Let's stockpile the Eternium in one place first, then head to the room with the Bronze Core.","TWN":"我們先把永恆之金聚集在一個地方，然後去青銅核心所在的房間吧。"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"좋아. 이쪽으로 가면 아무 일도 없을 거야.","JPN":"よし。こっちに行けば何もないはずよ。","ENG":"Okay. If we go this way, nothing will happen.","TWN":"好，往這邊走應該不會發生任何事。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"나탈리아, 네 쪽은 어때?","JPN":"ナタリア、そっちはどう？","ENG":"Natalia, what about your side?","TWN":"那塔利亞，妳那邊怎麼樣？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"LAUGH2"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};